import { memo } from "react";
import { UseFormReturn } from "react-hook-form";
import { CreateApplicationPayload } from "../../types/applications.types";
import {
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";

export const CityInput = memo(function CityInput({
  control,
}: {
  control: UseFormReturn<CreateApplicationPayload>["control"];
}) {
  return (
    <FormField
      control={control}
      name="city"
      render={({ field }) => (
        <FormItem>
          <FormLabel>City</FormLabel>
          <FormControl>
            <Input placeholder="e.g. New York" {...field} />
          </FormControl>
          <FormMessage />
        </FormItem>
      )}
    />
  );
});
