import { memo } from "react";
import { UseFormReturn } from "react-hook-form";
import { CreateApplicationPayload } from "../../types/applications.types";
import {
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { DynamicSelect } from "@/components/common/DynamicSelect";
import { APPLICATIONS_ROUTES } from "../../routes/applications.routes";

export const JobSelect = memo(function JobSelect({
  control,
}: {
  control: UseFormReturn<CreateApplicationPayload>["control"];
}) {
  return (
    <FormField
      control={control}
      name="job"
      render={({ field }) => (
        <FormItem>
          <FormLabel>Job</FormLabel>
          <FormControl>
            <DynamicSelect
              placeholder="Select a job"
              endpoint={APPLICATIONS_ROUTES.getApplicationsJobs}
              label="title"
              value="_id"
              field={field}
            />
          </FormControl>
          <FormMessage />
        </FormItem>
      )}
    />
  );
});