import { FileDropZone } from "@/components/common/FileDropZone";
import {
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { UseFormReturn } from "react-hook-form";
import { CreateApplicationPayload } from "../../types/applications.types";

export const FileInput = ({
  control,
  onFileSelect,
  onFileClear,
  disabled = false,
}: {
  control: UseFormReturn<CreateApplicationPayload>["control"];
  onFileSelect?: (file: File) => void;
  onFileClear?: () => void;
  disabled?: boolean;
}) => {
  return (
    <FormField
      control={control}
      name="resume"
      render={({ field }) => (
        <FormItem>
          <FormLabel>Resume</FormLabel>
          <FormControl>
            <FileDropZone
              acceptedTypes={[
                "application/pdf",
                "text/plain",
                "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
              ]}
              onFileSelect={(file: File) => {
                field.onChange(file);
                onFileSelect?.(file);
              }}
              onFileClear={() => {
                field.onChange(undefined);
                onFileClear?.();
              }}
              disabled={disabled}
              label="Upload Resume"
              description="PDF, TXT, or DOCX (max 2MB)"
            />
          </FormControl>
          <FormMessage />
        </FormItem>
      )}
    />
  );
};
