import { memo, useEffect, useMemo, useState } from "react";
import { UseFormReturn, useWatch } from "react-hook-form";
import { CreateApplicationPayload } from "../../types/applications.types";
import {
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import {
  Combobox,
  ComboboxContent,
  ComboboxEmpty,
  ComboboxInput,
  ComboboxItem,
  ComboboxList,
  ComboboxTrigger,
  ComboboxValue,
} from "@/components/ui/combobox";
import { useCountries } from "@/shared/hooks/useCountries";
import { Item } from "@/components/ui/item";

type CountryApiResponse = {
  flag?: string;
  idd?: {
    root?: string;
    suffixes?: string[];
  };
};

type PhoneCodeOption = {
  label: string;
  value: string;
};

const DEFAULT_PHONE_CODE = "+1";

export const PhoneNumberInput = memo(function PhoneNumberInput({
  control,
}: {
  control: UseFormReturn<CreateApplicationPayload>["control"];
}) {
  const [phoneCode, setPhoneCode] = useState(DEFAULT_PHONE_CODE);
  const [localNumber, setLocalNumber] = useState("");
  const [options, setOptions] = useState<PhoneCodeOption[]>([]);
  const [loadingOptions, setLoadingOptions] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const { countries } = useCountries();

  const phoneNumberValue = useWatch({
    control,
    name: "phoneNumber",
    defaultValue: "",
  });

  const phoneCodesOptions = useMemo(() => {
    return countries.map((country) => {
      return {
        label: `<img src="${country.flag}" alt="${country.name} flag" /> ${country.name} (${country.phoneCode})`,
        value: country.phoneCode,
      };
    });
  }, [countries]);

  return (
    <FormField
      control={control}
      name="phoneNumber"
      render={({ field }) => (
        <FormItem>
          <FormLabel>Phone Number</FormLabel>
          <div className="flex flex-col gap-2 sm:flex-row sm:items-start overflow-visible">
            <div>
              <Combobox
                items={phoneCodesOptions}
                itemToStringValue={(item: any) => item?.label}
                onValueChange={(value) => setPhoneCode(value)}
              >
                <ComboboxInput placeholder="Select a framework" />
                <ComboboxContent>
                  <ComboboxEmpty>No items found.</ComboboxEmpty>
                  <ComboboxList>
                    {(item) => (
                      <ComboboxItem
                        key={`${item.value} ${item.label}`}
                        value={item.value}
                      >
                        <Item>
                          <ItemContent>
                            <ItemTitle className="whitespace-nowrap">
                              {item.label}
                            </ItemTitle>
                            <ItemDescription>
                            </ItemDescription>
                          </ItemContent>
                        </Item>
                      </ComboboxItem>
                    )}
                  </ComboboxList>
                </ComboboxContent>
              </Combobox>
            </div>
            <FormControl>
              <Input
                placeholder="(555) 000-0000"
                value={localNumber}
                onChange={(event) => {
                  const nextNumber = event.target.value;
                  setLocalNumber(nextNumber);
                  const combined = `${phoneCode} ${nextNumber}`.trim();
                  field.onChange(combined);
                }}
                onBlur={field.onBlur}
                ref={field.ref}
                className="flex-1"
              />
            </FormControl>
          </div>
          <FormMessage />
        </FormItem>
      )}
    />
  );
});
